// Resolve is the only tenant-bootstrap query. token_hash is globally unique;
// every operation after this lookup must use the returned company_id.
func (q *Queries) ResolveExternalPersonalAccessByTokenHash(ctx context.Context, arg ResolveExternalPersonalAccessByTokenHashParams) (ResolveExternalPersonalAccessByTokenHashRow, error) {
	row := q.db.QueryRow(ctx, resolveExternalPersonalAccessByTokenHash, arg.Now, arg.TokenHash)
	var i ResolveExternalPersonalAccessByTokenHashRow
	err := row.Scan(
		&i.ID,
		&i.CompanyID,
		&i.CourseID,
		&i.CourseVersionID,
		&i.PartnerOwnerID,
		&i.ExternalLearnerID,
		&i.ExpectedEmail,
		&i.NormalizedExpectedEmail,
		&i.RecipientFirstName,
		&i.RecipientLastName,
		&i.DeadlineDays,
		&i.Status,
		&i.TokenHash,
		&i.TokenPrefix,
		&i.EnrollmentID,
		&i.RootAccessID,
		&i.RepeatOfAccessID,
		&i.AttemptNumber,
		&i.IssuedByID,
		&i.IssuedAt,
		&i.ActivatedAt,
		&i.TokenRotatedAt,
		&i.RevokedAt,
		&i.ClosedAt,
		&i.UpdatedAt,
		&i.CourseTitle,
		&i.LifecycleStatus,
		&i.DistributionStatus,
		&i.CourseVersionNumber,
		&i.CourseVersionTitle,
		&i.CourseVersionDescription,
		&i.CoverFileID,
		&i.CourseVersionStatus,
		&i.Sequential,
		&i.DeadlineExpired,
	)
	return i, err
}

const revokeExternalPersonalAccess = `-- name: RevokeExternalPersonalAccess :one
WITH target AS (
    SELECT access.id, access.company_id, access.enrollment_id
    FROM external_personal_accesses AS access
    WHERE access.company_id = $2
      AND access.id = $3
      AND access.partner_owner_id = $4
      AND access.status IN ('issued', 'activated')
    FOR UPDATE OF access
), revoked_enrollment AS (
    UPDATE course_enrollments AS enrollment
    SET access_status = 'revoked',
        updated_at = $1
    FROM target
    WHERE enrollment.company_id = target.company_id
      AND enrollment.id = target.enrollment_id
    RETURNING enrollment.id
)
UPDATE external_personal_accesses AS access
SET status = 'revoked',
    revoked_at = $1,
    updated_at = $1
FROM target
LEFT JOIN revoked_enrollment ON true
WHERE access.company_id = target.company_id
  AND access.id = target.id
RETURNING access.id, access.company_id, access.course_id,
    access.course_version_id, access.partner_owner_id,
    access.external_learner_id, access.expected_email,
    access.normalized_expected_email, access.recipient_first_name,
    access.recipient_last_name, access.deadline_days, access.status,
    access.token_prefix, access.enrollment_id, access.root_access_id,
    access.repeat_of_access_id, access.attempt_number,
    access.issued_by_id, access.issued_at, access.activated_at,
    access.token_rotated_at, access.revoked_at, access.closed_at,
    access.updated_at
`

